+fn log_ux_jsonl(test: &str, check: &str, passed: bool, notes: &str) {
+    if std::env::var("E2E_JSONL").is_ok() || std::env::var("CI").is_ok() {
+        eprintln!(r#"{{"test":"{test}","check":"{check}","passed":{passed},"notes":"{notes}"}}"#);
