+fn shift_key(ch: char) -> Event {
+    Event::Key(KeyEvent {
+        code: KeyCode::Char(ch),
+        modifiers: Modifiers::SHIFT,
+        kind: KeyEventKind::Press,
+    })
+}
+
+fn key_press(code: KeyCode) -> Event {
+    Event::Key(KeyEvent {
+        code,
+        modifiers: Modifiers::empty(),
+        kind: KeyEventKind::Press,
+    })
+}
