+        "Typing should auto-focus search and record query",
+    );
+
+    assert_eq!(focused, Some(true));
+    assert_eq!(query.as_deref(), Some("a"));
+}
+
+// =============================================================================
+// Focus / Navigation Tests
+// =============================================================================
+
+#[test]
+fn navigation_jk_moves_selection() {
+    let mut screen = VirtualizedSearch::new();
