+        // Verify content matches buffer
+        for y in 0..h {
+            for x in 0..w {
+                let buf_ch = next
+                    .get(x, y)
+                    .and_then(|c| c.content.as_char())
+                    .unwrap_or(' ');
+                let term_ch = rows[y as usize].chars().nth(x as usize).unwrap_or(' ');
